void resolver(int novita[], int gigante[], int inicio, int fin) {
  if (inicio >= fin) return;
  int medio = (inicio + fin) / 2;
  // Comparar posiciones actuales de Novita y Gigante
  // Llamadas recursivas para mitades
  resolver(novita, gigante, inicio, medio);
  resolver(novita, gigante, medio + 1, fin);
}
